1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type Damage = {
9	  itemType: string;
10	  amount: number;
11	};
12	
13	export type Incident = {
14	  cause: string;
15	  damages: Damage[];
16	};
17	
18	export type QuoteStep = { op: "quote"; items: Item[] };
19	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
20	export type Step = QuoteStep | ClaimStep;
21	
22	export type Scenario = {
23	  customer: { yearsWithMHPCO: number };
24	  steps: Step[];
25	};
26	
27	export type QuoteResult = { premium: number };
28	export type ClaimResult = { payout: number; remainingCap: number };
29	export type StepResult = QuoteResult | ClaimResult;
30	
31	export type ScenarioResult = {
32	  results: StepResult[];
33	};
34	
35	const PROCESSING_FEE = 5;
36	const FIRST_INSURANCE_SURCHARGE = 0.1;
37	const LOYALTY_DISCOUNT = 0.2;
38	const LOYALTY_THRESHOLD_YEARS = 2;
39	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
40	const CURSED_SURCHARGE = 0.5;
41	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
42	const HIGH_ENCHANTMENT_THRESHOLD = 5;
43	const DEDUCTIBLE_PER_DAMAGE = 100;
44	const CAP_MULTIPLIER = 2;
45	const DAMAGE_HIGH_ENCHANT_THRESHOLD = 8;
46	const DAMAGE_HIGH_ENCHANT_RATE = 0.5;
47	
48	const ITEM_BASE_PREMIUM: Record<string, number> = {
49	  sword: 100,
50	  amulet: 60,
51	  rune: 25,
52	  moonstone: 25,
53	};
54	
55	const ITEM_INSURANCE_VALUE: Record<string, number> = {
56	  sword: 1000,
57	  amulet: 600,
58	  rune: 250,
59	};
60	
61	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
62	const COMPONENT_BLOCK_SIZE = 3;
63	const COMPONENT_BLOCK_PREMIUM = 60;
64	
65	const groupCountsByType = (items: Item[]): Map<string, number> => {
66	  const counts = new Map<string, number>();
67	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
68	  return counts;
69	};
70	
71	const basePremiumForGroup = (type: string, count: number): number => {
72	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
73	  return count * ITEM_BASE_PREMIUM[type];
74	};
75	
76	const sumBasePremium = (counts: Map<string, number>): number => {
77	  let total = 0;
78	  for (const [type, count] of counts) total += basePremiumForGroup(type, count);
79	  return total;
80	};
81	
82	const isHighlyEnchanted = (item: Item): boolean =>
83	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
84	
85	const surchargeRateForItem = (item: Item): number =>
86	  (item.cursed ? CURSED_SURCHARGE : 0) +
87	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
88	
89	const surchargeForItem = (item: Item): number =>
90	  ITEM_BASE_PREMIUM[item.type] * surchargeRateForItem(item);
91	
92	const itemSurcharges = (items: Item[]): number =>
93	  items.reduce((total, item) => total + surchargeForItem(item), 0);
94	
95	const calculatePremium = (
96	  items: Item[],
97	  yearsWithMHPCO: number,
98	  isFollowUpContract: boolean,
99	): number => {
100	  const base = sumBasePremium(groupCountsByType(items));
101	  const surcharges = itemSurcharges(items);
102	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE;
103	  const loyaltyDiscount =
104	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT : 0;
105	  const followUpDiscount = isFollowUpContract ? base * FOLLOWUP_CONTRACT_DISCOUNT : 0;
106	  return Math.ceil(
107	    base + surcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
108	  );
109	};
110	
111	type Policy = {
112	  items: Item[];
113	  remainingCap: number;
114	};
115	
116	const insuranceSum = (items: Item[]): number =>
117	  items.reduce((sum, item) => sum + ITEM_INSURANCE_VALUE[item.type], 0);
118	
119	const reimbursableAmount = (damage: Damage, item: Item): number =>
120	  (item.enchantment ?? 0) >= DAMAGE_HIGH_ENCHANT_THRESHOLD
121	    ? damage.amount * DAMAGE_HIGH_ENCHANT_RATE
122	    : damage.amount;
123	
124	const payoutForDamage = (damage: Damage, item: Item): number =>
125	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE_PER_DAMAGE);
126	
127	const findInsuredItem = (policy: Policy, itemType: string): Item =>
128	  policy.items.find((item) => item.type === itemType)!;
129	
130	const grossPayoutForIncident = (policy: Policy, incident: Incident): number =>
131	  incident.damages.reduce(
132	    (sum, damage) => sum + payoutForDamage(damage, findInsuredItem(policy, damage.itemType)),
133	    0,
134	  );
135	
136	const claimPayout = (policy: Policy, incident: Incident): number =>
137	  Math.floor(Math.min(grossPayoutForIncident(policy, incident), policy.remainingCap));
138	
139	const handleQuote = (
140	  step: QuoteStep,
141	  policies: Policy[],
142	  yearsWithMHPCO: number,
143	): QuoteResult => {
144	  const isFollowUpContract = policies.length >= 1;
145	  policies.push({ items: step.items, remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER });
146	  return { premium: calculatePremium(step.items, yearsWithMHPCO, isFollowUpContract) };
147	};
148	
149	const handleClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
150	  const policy = policies[step.policy];
151	  const payout = claimPayout(policy, step.incident);
152	  policy.remainingCap -= payout;
153	  return { payout, remainingCap: policy.remainingCap };
154	};
155	
156	export const runScenario = (scenario: Scenario): ScenarioResult => {
157	  const policies: Policy[] = [];
158	  const results: StepResult[] = scenario.steps.map((step) =>
159	    step.op === "quote"
160	      ? handleQuote(step, policies, scenario.customer.yearsWithMHPCO)
161	      : handleClaim(step, policies),
162	  );
163	  return { results };
164	};
