1	import { readFileSync } from "node:fs";
2	import { runScenario, type Scenario } from "./claim-office.js";
3	
4	const KNOWN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);
5	
6	const findUnknownItemTypeInQuote = (scenario: Scenario): string | undefined => {
7	  for (const step of scenario.steps) {
8	    if (step.op !== "quote") continue;
9	    for (const item of step.items) {
10	      if (!KNOWN_ITEM_TYPES.has(item.type)) return item.type;
11	    }
12	  }
13	  return undefined;
14	};
15	
16	const findClaimAgainstUninsuredItem = (scenario: Scenario): string | undefined => {
17	  const insuredTypes: Set<string>[] = [];
18	  for (const step of scenario.steps) {
19	    if (step.op === "quote") {
20	      insuredTypes.push(new Set(step.items.map((item) => item.type)));
21	      continue;
22	    }
23	    const policyTypes = insuredTypes[step.policy];
24	    for (const damage of step.incident.damages) {
25	      if (!policyTypes?.has(damage.itemType)) return damage.itemType;
26	    }
27	  }
28	  return undefined;
29	};
30	
31	const die = (message: string): never => {
32	  process.stderr.write(`${message}\n`);
33	  process.exit(1);
34	};
35	
36	const scenario: Scenario = JSON.parse(readFileSync(0, "utf-8"));
37	
38	const unknownType = findUnknownItemTypeInQuote(scenario);
39	if (unknownType !== undefined) die(`Unknown item type: ${unknownType}`);
40	
41	const uninsuredItemType = findClaimAgainstUninsuredItem(scenario);
42	if (uninsuredItemType !== undefined) die(`Claim references item not in policy: ${uninsuredItemType}`);
43	
44	process.stdout.write(JSON.stringify(runScenario(scenario)));
